using UnityEngine;
using System;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 0;
    public int level = 1;
    public int experience = 0;
    public float attackDamage = 10f;
    public float defense = 5f;
    public int premiumCurrency = 0;

    void Start()
    {
        currentHealth = maxHealth;
    }

    public void TakeDamage(int damage)
    {
        int actualDamage = Mathf.Max(0, damage - (int)defense);
        currentHealth -= actualDamage;
        
        if (currentHealth <= 0)
        {
            currentHealth = 0;
            Die();
        }
    }

    public void Heal(int amount)
    {
        currentHealth += amount;
        if (currentHealth > maxHealth)
        {
            currentHealth = maxHealth;
        }
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
    }

    public void AddPremiumCurrency(int amount)
    {
        premiumCurrency += amount;
    }

    public void AddExperience(int amount)
    {
        experience += amount;
        CheckLevelUp();
    }

    void CheckLevelUp()
    {
        int requiredExp = level * 100;
        if (experience >= requiredExp)
        {
            level++;
            experience -= requiredExp;
            maxHealth += 20;
            currentHealth = maxHealth;
            attackDamage += 2f;
            defense += 1f;
        }
    }

    void Die()
    {
        Debug.Log("Player died!");
    }
}

public class DamageCalculator : MonoBehaviour
{
    public static int CalculateDamage(float baseDamage, float attackerLevel, float defenderDefense, bool isCritical)
    {
        float damage = baseDamage * (1 + (attackerLevel * 0.1f));
        
        if (isCritical)
        {
            damage *= 2f;
        }
        
        damage -= defenderDefense;
        
        return Mathf.Max(1, (int)damage);
    }

    public static bool IsCriticalHit(float critChance)
    {
        return UnityEngine.Random.Range(0f, 100f) < critChance;
    }

    public static int CalculateElementalDamage(int baseDamage, string attackerElement, string defenderElement)
    {
        float multiplier = 1f;
        
        if (attackerElement == "Fire" && defenderElement == "Ice")
            multiplier = 1.5f;
        else if (attackerElement == "Ice" && defenderElement == "Fire")
            multiplier = 0.5f;
        else if (attackerElement == "Water" && defenderElement == "Fire")
            multiplier = 1.5f;
        else if (attackerElement == "Fire" && defenderElement == "Water")
            multiplier = 0.5f;
        
        return (int)(baseDamage * multiplier);
    }
}

public class ShopItem
{
    public string itemName;
    public string description;
    public int price;
    public int premiumPrice;
    public string itemType;
    public int value;
    public bool isPremium;

    public ShopItem(string name, string desc, int regularPrice, int premPrice, string type, int val, bool premium = false)
    {
        itemName = name;
        description = desc;
        price = regularPrice;
        premiumPrice = premPrice;
        itemType = type;
        value = val;
        isPremium = premium;
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public ShopItem[] shopItems;

    void Start()
    {
        InitializeShop();
    }

    void InitializeShop()
    {
        shopItems = new ShopItem[]
        {
            new ShopItem("Health Potion", "Restores 50 HP", 50, 0, "consumable", 50),
            new ShopItem("Large Health Potion", "Restores 100 HP", 100, 0, "consumable", 100),
            new ShopItem("Iron Sword", "Increases attack by 5", 200, 0, "weapon", 5),
            new ShopItem("Steel Armor", "Increases defense by 3", 300, 0, "armor", 3),
            new ShopItem("Premium Sword", "Increases attack by 15", 0, 50, "weapon", 15, true),
            new ShopItem("Premium Armor", "Increases defense by 10", 0, 100, "armor", 10, true),
            new ShopItem("Currency Pack Small", "500 coins", 0, 10, "currency", 500, true),
            new ShopItem("Currency Pack Large", "2000 coins", 0, 30, "currency", 2000, true)
        };
    }

    public bool PurchaseItem(int itemIndex)
    {
        if (itemIndex < 0 || itemIndex >= shopItems.Length)
            return false;

        ShopItem item = shopItems[itemIndex];
        
        if (item.isPremium)
        {
            if (playerStats.premiumCurrency >= item.premiumPrice)
            {
                playerStats.premiumCurrency -= item.premiumPrice;
                ApplyItemEffect(item);
                return true;
            }
        }
        else
        {
            if (playerStats.currency >= item.price)
            {
                playerStats.currency -= item.price;
                ApplyItemEffect(item);
                return true;
            }
        }
        
        return false;
    }

    void ApplyItemEffect(ShopItem item)
    {
        switch (item.itemType)
        {
            case "consumable":
                playerStats.Heal(item.value);
                break;
            case "weapon":
                playerStats.attackDamage += item.value;
                break;
            case "armor":
                playerStats.defense += item.value;
                break;
            case "currency":
                playerStats.AddCurrency(item.value);
                break;
        }
    }

    public int CalculateDiscountedPrice(int originalPrice, float discountPercent)
    {
        return (int)(originalPrice * (1f - discountPercent / 100f));
    }

    public int CalculateBundlePrice(int[] itemIndices)
    {
        int totalPrice = 0;
        foreach (int index in itemIndices)
        {
            if (index >= 0 && index < shopItems.Length)
            {
                totalPrice += shopItems[index].price;
            }
        }
        return (int)(totalPrice * 0.8f);
    }
}

public class Enemy : MonoBehaviour
{
    public int health = 50;
    public float attackDamage = 8f;
    public int level = 1;
    public string elementType = "Normal";
    public int currencyReward = 25;
    public int experienceReward = 50;

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health <= 0)
        {
            Die();
        }
    }

    void Die()
    {
        PlayerStats player = FindObjectOfType<PlayerStats>();
        if (player != null)
        {
            player.AddCurrency(currencyReward);
            player.AddExperience(experienceReward);
        }
        Destroy(gameObject);
    }

    public void AttackPlayer(PlayerStats player)
    {
        bool isCrit = DamageCalculator.IsCriticalHit(10f);
        int damage = DamageCalculator.CalculateDamage(attackDamage, level, player.defense, isCrit);
        player.TakeDamage(damage);
    }
}

public class CombatSystem : MonoBehaviour
{
    public PlayerStats player;
    public Enemy currentEnemy;

    public void PlayerAttack()
    {
        if (currentEnemy == null) return;

        bool isCrit = DamageCalculator.IsCriticalHit(15f);
        int damage = DamageCalculator.CalculateDamage(player.attackDamage, player.level, 0, isCrit);
        
        currentEnemy.TakeDamage(damage);
    }

    public void EnemyAttack()
    {
        if (currentEnemy == null) return;
        currentEnemy.AttackPlayer(player);
    }
}

public class InAppPurchaseManager : MonoBehaviour
{
    public PlayerStats playerStats;

    public void PurchasePremiumCurrency(int amount, float realPrice)
    {
        playerStats.AddPremiumCurrency(amount);
    }

    public void PurchaseCurrencyPack(string packSize)
    {
        switch (packSize)
        {
            case "small":
                playerStats.AddCurrency(500);
                break;
            case "medium":
                playerStats.AddCurrency(1500);
                break;
            case "large":
                playerStats.AddCurrency(5000);
                break;
        }
    }

    public void PurchaseStarterPack()
    {
        playerStats.AddCurrency(1000);
        playerStats.AddPremiumCurrency(50);
        playerStats.attackDamage += 10f;
        playerStats.defense += 5f;
    }
}

public class PriceCalculator : MonoBehaviour
{
    public static int CalculateDynamicPrice(int basePrice, int playerLevel)
    {
        return (int)(basePrice * (1 + (playerLevel * 0.05f)));
    }

    public static int CalculateUpgradePrice(int currentLevel)
    {
        return 100 * currentLevel * currentLevel;
    }

    public static int CalculateRepairCost(int maxDurability, int currentDurability, int itemValue)
    {
        float damagePercent = 1f - ((float)currentDurability / maxDurability);
        return (int)(itemValue * damagePercent * 0.5f);
    }
}

public class GameManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public ShopManager shopManager;
    public CombatSystem combatSystem;

    void Start()
    {
        playerStats = GetComponent<PlayerStats>();
        shopManager = GetComponent<ShopManager>();
        combatSystem = GetComponent<CombatSystem>();
    }

    public void SaveGame()
    {
        PlayerPrefs.SetInt("PlayerHealth", playerStats.currentHealth);
        PlayerPrefs.SetInt("PlayerCurrency", playerStats.currency);
        PlayerPrefs.SetInt("PlayerLevel", playerStats.level);
        PlayerPrefs.SetInt("PlayerExperience", playerStats.experience);
        PlayerPrefs.SetFloat("PlayerAttack", playerStats.attackDamage);
        PlayerPrefs.SetFloat("PlayerDefense", playerStats.defense);
        PlayerPrefs.SetInt("PremiumCurrency", playerStats.premiumCurrency);
        PlayerPrefs.Save();
    }

    public void LoadGame()
    {
        playerStats.currentHealth = PlayerPrefs.GetInt("PlayerHealth", 100);
        playerStats.currency = PlayerPrefs.GetInt("PlayerCurrency", 0);
        playerStats.level = PlayerPrefs.GetInt("PlayerLevel", 1);
        playerStats.experience = PlayerPrefs.GetInt("PlayerExperience", 0);
        playerStats.attackDamage = PlayerPrefs.GetFloat("PlayerAttack", 10f);
        playerStats.defense = PlayerPrefs.GetFloat("PlayerDefense", 5f);
        playerStats.premiumCurrency = PlayerPrefs.GetInt("PremiumCurrency", 0);
    }
}